 73â†’    val future = CompletableFuture<T>()
 74â†’    setupCancellation(future)
 75â†’    invokeOnCompletion {
 76â†’        try {
 77â†’            future.complete(getCompleted())
 78â†’        } catch (t: Throwable) {
 79â†’            future.completeExceptionally(t)
 80â†’        }
 81â†’    }
 82â†’    return future
 83â†’}
