107â†’/**
108â†’ * Converts this [CompletionStage] to an instance of [Deferred].
109â†’ *
110â†’ * The [CompletableFuture] that corresponds to this [CompletionStage] (see [CompletionStage.toCompletableFuture])
111â†’ * is cancelled when the resulting deferred is cancelled.
112â†’ */
113â†’@Suppress("DeferredIsResult")
114â†’public fun <T> CompletionStage<T>.asDeferred(): Deferred<T> {
115â†’    val future = toCompletableFuture() // retrieve the future
116â†’    // Fast path if already completed
117â†’    if (future.isDone) {
118â†’        return try {
119â†’            @Suppress("UNCHECKED_CAST")
120â†’            CompletableDeferred(future.get() as T)
121â†’        } catch (e: Throwable) {
122â†’            // unwrap original cause from ExecutionException
123â†’            val original = (e as? ExecutionException)?.cause ?: e
124â†’            CompletableDeferred<T>().also { it.completeExceptionally(original) }
125â†’        }
126â†’    }
127â†’    val result = CompletableDeferred<T>()
128â†’    handle { value, exception ->
129â†’        try {
130â†’            if (exception == null) {
131â†’                // the future has completed normally
132â†’                result.complete(value)
133â†’            } else {
134â†’                // the future has completed with an exception, unwrap it consistently with fast path
135â†’                // Note: In the fast-path the implementation of CompletableFuture.get() does unwrapping
136â†’                result.completeExceptionally((exception as? CompletionException)?.cause ?: exception)
137â†’            }
138â†’        } catch (e: Throwable) {
139â†’            // We come here iff the internals of Deferred threw an exception during its completion
140â†’            handleCoroutineException(EmptyCoroutineContext, e)
141â†’        }
142â†’    }
143â†’    result.cancelFutureOnCompletion(future)
144â†’    return result
145â†’}
146â†’
147â†’/**
148â†’ * Awaits for completion of [CompletionStage] without blocking a thread.
149â†’ *
150â†’ * This suspending function is cancellable.
151â†’ * If the [Job] of the current coroutine is cancelled or completed while this suspending function is waiting, this function
152â†’ * stops waiting for the completion stage and immediately resumes with [CancellationException][kotlinx.coroutines.CancellationException].
153â†’ *
154â†’ * This method is intended to be used with one-shot futures, so on coroutine cancellation the [CompletableFuture] that
155â†’ * corresponds to this [CompletionStage] (see [CompletionStage.toCompletableFuture])
156â†’ * is cancelled. If cancelling the given stage is undesired, `stage.asDeferred().await()` should be used instead.
157â†’ */
158â†’public suspend fun <T> CompletionStage<T>.await(): T {
159â†’    val future = toCompletableFuture() // retrieve the future
160â†’    // fast path when CompletableFuture is already done (does not suspend)
161â†’    if (future.isDone) {
162â†’        try {
163â†’            @Suppress("UNCHECKED_CAST", "BlockingMethodInNonBlockingContext")
164â†’            return future.get() as T
165â†’        } catch (e: ExecutionException) {
166â†’            throw e.cause ?: e // unwrap original cause from ExecutionException
167â†’        }
168â†’    }
169â†’    // slow path -- suspend
170â†’    return suspendCancellableCoroutine { cont: CancellableContinuation<T> ->
171â†’        val consumer = ContinuationHandler(cont)
172â†’        handle(consumer)
173â†’        cont.invokeOnCancellation {
174â†’            future.cancel(false)
175â†’            consumer.cont = null // shall clear reference to continuation to aid GC
176â†’        }
177â†’    }
178â†’}
179â†’
180â†’private class ContinuationHandler<T>(
181â†’    @Volatile @JvmField var cont: Continuation<T>?
182â†’) : BiFunction<T?, Throwable?, Unit> {
183â†’    @Suppress("UNCHECKED_CAST")
184â†’    override fun apply(result: T?, exception: Throwable?) {
185â†’        val cont = this.cont ?: return // atomically read current value unless null
186â†’        if (exception == null) {
187â†’            // the future has completed normally
188â†’            cont.resume(result as T)
189â†’        } else {
190â†’            // the future has completed with an exception, unwrap it to provide consistent view of .await() result and to propagate only original exception
191â†’            cont.resumeWithException((exception as? CompletionException)?.cause ?: exception)
192â†’        }
193â†’    }
194â†’}
